function minInteger(num, k) {
    if (k === 0) return num;
    num = num.split('');
    const n = num.length;
    for (let i = 0; i < n; ++i) {
        let idx = i;
        for (let j = i + 1; j < n && j - i <= k; ++j) {
            if (num[j] < num[idx]) {
                idx = j;
            }
        }
        const minDigit = num[idx];
        for (let j = idx; j > i; --j) {
            num[j] = num[j - 1];
        }
        num[i] = minDigit;
        k -= idx - i;
    }
    return num.join('');
}
