public String minInteger(String num, int k) {
    if (k == 0) return num;
    int n = num.length();
    char[] arr = num.toCharArray();
    for (int i = 0; i < n; ++i) {
        int idx = i;
        for (int j = i + 1; j < n && j - i <= k; ++j) {
            if (arr[j] < arr[idx]) {
                idx = j;
            }
        }
        char minDigit = arr[idx];
        for (int j = idx; j > i; --j) {
            arr[j] = arr[j - 1];
        }
        arr[i] = minDigit;
        k -= idx - i;
    }
    return new String(arr);
}
